/*
 * log10f() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly log10f  (test_log10f_opt.elf)
 *   2. Linked with toolchain's default log10f        (test_log10f_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    float r = log10f(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values: log10(x) for x near 0 */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-10f);
    emit(-1.0e-10f);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    emit(2.0f);     /* log10(2) */
    emit(10.0f);    /* log10(10) -> 1 */
    emit(1.0f);     /* log10(1) -> 0 */
    emit(100.0f);   /* log10(100) -> 2 */
    emit(1000.0f);  /* log10(1000) -> 3 */
    emit(0.1f);     /* log10(0.1) -> -1 */
    emit(0.01f);    /* log10(0.01) -> -2 */
    emit(0.001f);   /* log10(0.001) -> -3 */
    emit(0.5f);
    emit(5.0f);
}

/* 4. Large arguments */
static void test_large(void)
{
    float vals[] = {
        1.0e10f, 1.0e20f, FLT_MAX,
        10.0f, 100.0f, 1000.0f, 10000.0f, 100000.0f,
        -1.0f, -10.0f, -100.0f, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Powers of 10 (simple log10 values) and values near 1.0 */
static void test_quadrant(void)
{
    float one = 1.0f;
    float offsets[] = { -1e-5f, -1e-6f, 0.0f, 1e-6f, 1e-5f };
    int noff = sizeof(offsets) / sizeof(offsets[0]);

    for (int j = 0; j < noff; j++)
        emit(one + offsets[j]);

    /* Powers of 10 (simple log10 values) */
    float powers[] = { 0.001f, 0.01f, 0.1f, 1.0f, 10.0f, 100.0f, 1000.0f, 10000.0f, 100000.0f, 1000000.0f };
    int npow = sizeof(powers) / sizeof(powers[0]);
    for (int k = 0; k < npow; k++)
        emit(powers[k]);
}

/* 6. Worst-case argument values */
static void test_hard(void)
{
    float cases[] = {
        u2f(0x3f800001u), /* 1.0 + ULP, near log10(1)=0 */
        u2f(0x3f7fffffu), /* just below 1.0 */
        u2f(0x41200000u), /* 10.0 */
        u2f(0x42200000u), /* 40.0 */
        u2f(0x42c80000u), /* 100.0 */
        0.999999940f,      /* near 1.0 */
        1.000000060f,
        2.0f, 5.0f, 20.0f, 50.0f, 200.0f, 500.0f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        if (cases[i] > 0.0f)
            emit(-cases[i]);
    }
}

/* 7. Sweep [1, 10] in 200 steps */
static void test_sweep(void)
{
    float lo = 1.0f;
    float hi = 10.0f;
    int nsteps = 200;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (float)i * step);
}

/* 8. Sample [1, 2] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t start = 0x3f800000u; /* 1.0 */
    uint32_t end   = 0x40000000u; /* 2.0 */
    for (uint32_t b = start; b <= end; b += 4194304)
        emit_u(b);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

