/*
 * acosf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly acosf  (test_acosf_opt.elf)
 *   2. Linked with toolchain's default acosf        (test_acosf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    float r = acosf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity (out of domain) */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values: acos(0) ~ pi/2 */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-10f);
    emit(-1.0e-10f);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    float pi_2 = 1.57079632679489661923f;
    float pi_6 = 0.52359877559829887308f;

    emit(-1.0f);
    emit(-0.999f);
    emit(-0.5f);
    emit(-pi_6);
    emit(0.0f);
    emit(pi_6);
    emit(0.5f);
    emit(0.999f);
    emit(1.0f);
    emit(pi_2);
}

/* 4. Large arguments (domain boundary) */
static void test_large(void)
{
    float vals[] = {
        1.5f, -1.5f, 2.0f, -2.0f, 10.0f, -10.0f,
        100.0f, -100.0f, FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Quadrant transitions (domain boundaries) */
static void test_quadrant(void)
{
    float offsets[] = { -1e-5f, 0.0f, 1e-5f };
    int noff = sizeof(offsets) / sizeof(offsets[0]);

    float boundaries[] = { -1.0f, 1.0f };
    int nbnd = sizeof(boundaries) / sizeof(boundaries[0]);

    for (int k = 0; k < nbnd; k++) {
        for (int j = 0; j < noff; j++)
            emit(boundaries[k] + offsets[j]);
    }
}

/* 6. Hard cases near domain boundaries */
static void test_hard(void)
{
    float cases[] = {
        u2f(0x3f800000u), /* 1.0 */
        u2f(0xbf800000u), /* -1.0 */
        u2f(0x3f7fffffu), /* 1.0 - ULP */
        u2f(0xbf7fffffu), /* -1.0 + ULP */
        0.9999999f, -0.9999999f,
        0.99999999f, -0.99999999f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++)
        emit(cases[i]);
}

/* 7. Sweep [-1, 1] in 200 steps */
static void test_sweep(void)
{
    int nsteps = 200;
    for (int i = 0; i <= nsteps; i++)
        emit(-1.0f + 2.0f * (float)i / (float)nsteps);
}

/* 8. Exhaustive [-1, 1] every 65536 ULP */
static void test_exhaustive_small(void)
{
    uint32_t start = 0xbf800000u; /* -1.0 */
    uint32_t end = 0x3f800000u;   /* 1.0 */
    for (uint32_t b = start; b <= end; b += 65536) {
        if (b >= start && b <= end)
            emit_u(b);
    }
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

