/*
 * ldexpf() test harness — prints (input_hex, exponent, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly ldexpf  (test_ldexpf_opt.elf)
 *   2. Linked with toolchain's default ldexpf        (test_ldexpf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x, int exp)
{
    float r = ldexpf(x, exp);
    printf("%08lx %d %08lx\n",
           (unsigned long)f2u(x), exp, (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits, int exp)
{
    emit(u2f(bits), exp);
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    int exps[] = { 0, 1, -1, 10, -10 };
    int ne = sizeof(exps) / sizeof(exps[0]);

    /* Zeros with various exponents */
    for (int j = 0; j < ne; j++) {
        emit(0.0f, exps[j]);
        emit(-0.0f, exps[j]);
    }

    /* NaN */
    emit_u(0x7fc00000u, 5);   /* qNaN */
    emit_u(0x7f800001u, 5);   /* sNaN */
    emit_u(0xffc00000u, 5);   /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u, 5);   /* +Inf */
    emit_u(0xff800000u, 5);   /* -Inf */
}

/* 2. Tiny mantissa values with various exponents */
static void test_tiny(void)
{
    int exps[] = { 0, 1, -1, 10, -10, 100, -100 };

    emit_u(0x00000001u, exps[0]); /* min denorm */
    emit_u(0x80000001u, exps[0]);
    emit(FLT_MIN, exps[3]);
    emit(-FLT_MIN, exps[3]);
    emit(1.0e-30f, exps[6]);
    emit(-1.0e-30f, exps[6]);
}

/* 3. Known values: normalize frexp output */
static void test_known(void)
{
    /* frexp returns mantissa in [0.5, 1) with matching exponent */
    float mantissas[] = { 0.5f, 0.75f, 1.0f, -0.5f, -0.75f, -1.0f };
    int exponents[] = { 0, 1, 2, 5, 10, -5, -10 };

    for (int i = 0; i < 6; i++) {
        for (int j = 0; j < 7; j++) {
            emit(mantissas[i], exponents[j]);
        }
    }
}

/* 4. Large exponents (overflow/underflow transitions) */
static void test_large_exp(void)
{
    float vals[] = { 0.5f, 1.0f, -1.0f, FLT_MAX };
    int exps[] = { 127, 126, -126, -127, 200, -200 };

    for (int i = 0; i < 4; i++) {
        for (int j = 0; j < 6; j++) {
            emit(vals[i], exps[j]);
        }
    }
}

/* 6. Exponent zero (identity) */
static void test_zero_exponent(void)
{
    float vals[] = {
        0.1f, 0.5f, 1.0f, 1.5f, 2.0f, 10.0f, 100.0f,
        -0.1f, -0.5f, -1.0f, -1.5f, -2.0f, -10.0f, -100.0f,
        FLT_MIN, FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i], 0);
}

/* 7. Worst-case exponent combinations */
static void test_hard_exponents(void)
{
    float bases[] = { 0.5f, 1.0f, 1.5f, -1.0f, -2.0f };
    int exps[] = { -50, -25, 0, 25, 50, 100, -100, 126, -126 };

    for (int i = 0; i < 5; i++) {
        for (int j = 0; j < 9; j++) {
            emit(bases[i], exps[j]);
        }
    }
}

/* 7b. Sweep exponent range with fixed base */
static void test_sweep_exponent(void)
{
    float base = 1.0f;
    int exps[] = { -100, -50, -10, -5, -1, 0, 1, 5, 10, 50, 100 };
    int ne = sizeof(exps) / sizeof(exps[0]);

    for (int j = 0; j < ne; j++)
        emit(base, exps[j]);
}

/* 8. Sample mantissa [0.5, 1) with base exponent */
static void test_exhaustive_small(void)
{
    uint32_t start = 0x3f000000u; /* 0.5 */
    uint32_t end = 0x3f800000u;   /* 1.0 */
    int exp = 10;

    for (uint32_t b = start; b <= end; b += 2097152)
        emit_u(b, exp);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large_exp();
    test_zero_exponent();
    test_hard_exponents();
    test_sweep_exponent();
    test_exhaustive_small();
    return 0;
}

